+package com.example.billing;
+
+import com.stripe.Stripe;
+import com.stripe.exception.StripeException;
+import com.stripe.model.checkout.Session;
+import com.stripe.param.checkout.SessionCreateParams;
+import org.springframework.stereotype.Service;
+
+@Service
+public class CheckoutService {
+
+    private final StripeProperties props;
+
+    public CheckoutService(StripeProperties props) {
+        Stripe.apiKey = props.apiKey();
+        this.props = props;
+    }
+
+    public String createCheckoutSession(String userId, String priceId) throws StripeException {
+        SessionCreateParams params = SessionCreateParams.builder()
+                .setMode(SessionCreateParams.Mode.SUBSCRIPTION)
+                .setSuccessUrl(props.successUrl() + "?session_id={CHECKOUT_SESSION_ID}")
+                .setCancelUrl(props.cancelUrl())
+                .addLineItem(SessionCreateParams.LineItem.builder()
+                        .setPrice(priceId)
+                        .setQuantity(1L)
+                        .build())
+                .putMetadata("userId", userId)
+                .build();
+        return Session.create(params).getUrl();
+    }
+}

