+package com.example.billing;
+
+import org.springframework.http.ResponseEntity;
+import org.springframework.security.core.annotation.AuthenticationPrincipal;
+import org.springframework.security.core.userdetails.UserDetails;
+import org.springframework.web.bind.annotation.*;
+
+@RestController
+@RequestMapping("/api/billing")
+public class SubscriptionController {
+
+    private final CheckoutService checkoutService;
+    private final SubscriptionRepository subscriptionRepository;
+
+    @PostMapping("/checkout")
+    public ResponseEntity<CheckoutResponse> startCheckout(
+            @RequestBody CheckoutRequest req,
+            @AuthenticationPrincipal UserDetails user) throws StripeException {
+        String url = checkoutService.createCheckoutSession(user.getUsername(), req.priceId());
+        return ResponseEntity.ok(new CheckoutResponse(url));
+    }
+
+    @GetMapping("/status")
+    public ResponseEntity<SubscriptionStatus> getStatus(
+            @AuthenticationPrincipal UserDetails user) {
+        return ResponseEntity.ok(subscriptionRepository.findByUserId(user.getUsername()));
+    }
+}

