+package com.example.webhook;
+
+import com.stripe.model.Event;
+import com.stripe.net.Webhook;
+import org.springframework.http.ResponseEntity;
+import org.springframework.web.bind.annotation.*;
+
+@RestController
+@RequestMapping("/api/webhooks")
+public class StripeWebhookHandler {
+
+    private final SubscriptionService subscriptionService;
+    private final String webhookSecret;
+
+    @PostMapping("/stripe")
+    public ResponseEntity<Void> handleStripeEvent(
+            @RequestBody String payload,
+            @RequestHeader("Stripe-Signature") String signature) throws Exception {
+        Event event = Webhook.constructEvent(payload, signature, webhookSecret);
+        switch (event.getType()) {
+            case "customer.subscription.created" -> subscriptionService.activate(event);
+            case "customer.subscription.deleted" -> subscriptionService.cancel(event);
+            case "invoice.payment_failed"        -> subscriptionService.notifyFailed(event);
+        }
+        return ResponseEntity.ok().build();
+    }
+}
